  "integration_assessment": {
    "component_interactions": [
      {
        "from": "application_instances",
        "to": "user_preferences_table",
        "status": "risk",
        "issue": "During Step 4 rolling deployment, instances are split: some read from users.preferences_json, others from user_preferences. No feature flag to coordinate atomic switchover. If backfill was incomplete, new-code instances return missing preferences for unbackfilled users."
      },
      {
        "from": "backfill_job",
        "to": "user_preferences_table",
        "status": "broken",
        "issue": "Critical race condition: backfill (Step 3) runs concurrently with dual-write (Step 2). Backfill can read stale preferences_json at T1, then a user updates at T2 (dual-write puts fresh data in both tables), then backfill writes stale data to user_preferences at T3 — silently overwriting the newer value. This is a data-loss scenario."
      },
      {
        "from": "backfill_job",
        "to": "users_table",
        "status": "risk",
        "issue": "Backfill has no progress tracking or resumability. A failure partway through leaves an unknown subset of users unbackfilled with no way to determine which users were missed without a full re-scan."
      }
    ],
    "contract_compliance": "The dual-write contract in Steps 2-4 is sound in principle, but the lack of a coordination mechanism (feature flag) between instances during Step 4 means the read contract is inconsistent across the fleet during the rolling deploy window.",
    "data_flow_integrity": "Compromised. Three integrity gaps: (1) backfill-vs-dual-write race can silently lose recent user preference changes, (2) no validation gate between backfill completion and read switchover, (3) during rolling deploy in Step 4, different instances may return different preference values for the same user if backfill is incomplete."
  },

  "observability_review": {
    "logging": {
      "coverage": "missing",
      "gaps": [
        "No logging specified for the backfill job — progress, errors, rows processed, rows skipped",
        "No logging for dual-write failures (e.g., new table write fails but old succeeds — silent divergence)",
        "No logging to distinguish which read source an instance is currently using during rollout"
      ]
    },
    "metrics": {
      "coverage": "missing",
      "gaps": [
        "No metric for backfill progress (rows processed / total rows)",
        "No metric comparing read results between old and new tables (shadow-read validation)",
        "No metric for dual-write latency overhead",
        "No metric for dual-write divergence (writes that succeed on one table but fail on the other)",
        "No row-count or checksum comparison metric between tables post-backfill"
      ]
    },
    "tracing": {
      "coverage": "missing",
      "gaps": [
        "No trace annotation indicating which table a given request read from — impossible to debug user-reported stale data during rollout"
      ]
    },
    "debugging_capability": "Very poor. If a user reports stale preferences during the migration, an on-call engineer has no way to determine: (a) whether the user was backfilled, (b) whether the backfill overwrote a newer value, (c) which instance served the request and which table it read from. Debugging would require manual database inspection with no tooling support."
  },

  "resilience_assessment": {
    "failure_modes": [
      {
        "scenario": "Backfill job crashes partway through (OOM, timeout, DB connection drop)",
        "handling": "unhandled",
        "recommendation": "Add cursor-based progress tracking (e.g., last processed user_id) persisted to a checkpoint table or file. Implement idempotent upsert (INSERT ON CONFLICT UPDATE with a WHERE clause comparing updated_at timestamps) so re-runs are safe and don't overwrite newer data."
      },
      {
        "scenario": "Backfill overwrites a preference that was updated via dual-write after the backfill read but before it wrote",
        "handling": "unhandled",
        "recommendation": "Use a conditional write: UPDATE user_preferences SET ... WHERE updated_at < source.updated_at, or use INSERT ON CONFLICT DO UPDATE ... WHERE excluded.updated_at > user_preferences.updated_at. This ensures backfill never overwrites newer data."
      },
      {
        "scenario": "Dual-write fails on new table but succeeds on old table (or vice versa)",
        "handling": "unhandled",
        "recommendation": "Wrap dual-write in error handling that logs divergence. Decide on a policy: fail the request (strong consistency) or log-and-continue (eventual consistency with async reconciliation). Either way, emit a metric for dual-write failures."
      },
      {
        "scenario": "Step 4 deployed before backfill completes — users with no row in user_preferences get null/empty preferences",
        "handling": "unhandled",
        "recommendation": "Add a validation gate: before Step 4, run a query comparing COUNT(*) and a sample checksum between the two data sources. Block deployment if the counts diverge beyond a threshold. Alternatively, the read code should fall back to users.preferences_json if no row exists in user_preferences."
      },
      {
        "scenario": "Need to rollback from Step 4 to Step 3 (revert to reading from old table)",
        "handling": "partial",
        "recommendation": "Since dual-write is still active in Step 4, rollback is conceptually possible by redeploying old code. But without a feature flag, rollback requires a full redeployment — document this as the rollback plan and test it."
      }
    ],
    "retry_config": "Not specified. Backfill job should have per-row retry with exponential backoff to handle transient DB errors without aborting the entire job.",
    "timeout_config": "Not specified. Backfill job needs a per-batch timeout and overall job timeout. Dual-write needs a timeout on the secondary write to prevent doubling request latency if the new table is slow.",
    "circuit_breakers": "Not specified. Dual-write to the new table should have a circuit breaker — if the new table is down, the primary write path (old table) should not be affected. Fail-open on the new table write.",
    "graceful_degradation": "Missing. The read path in Step 4 has no fallback. If user_preferences table has no row for a user (incomplete backfill), the application should fall back to reading users.preferences_json rather than returning empty/null preferences."
  },

  "operational_readiness": {
    "deployment_ready": false,
    "rollback_capable": false,
    "rollback_plan": "No rollback plan documented. In principle, Steps 1-3 are additive and safe to roll back. Step 4 can be rolled back by redeploying the dual-read code, but only because Step 5 hasn't executed yet. Step 5 (stop dual-write) is the point of no easy return. Step 6 (drop column) is irreversible. Each step needs an explicit rollback procedure documented.",
    "monitoring_coverage": "None specified. Migration of this complexity requires: backfill progress dashboard, dual-write success/failure rates, table row count comparison, read-source annotation per request, and preference-load error rates split by source table.",
    "on_call_documentation": "Missing. On-call engineers need a runbook covering: how to identify which migration step the system is in, how to check backfill completeness, how to force-rollback the read source, how to reconcile diverged data between tables, and how to re-run the backfill safely.",
    "new_infrastructure_required": {
      "new_env_vars": [],
      "new_services": [],
      "new_queues_topics": [],
      "config_changes": [
        "Feature flag for read-source switching (strongly recommended to replace rolling-deploy-based cutover)",
        "Backfill checkpoint storage (table or config for resumability)"
      ],
      "infra_provisioning": [
        "user_preferences table with appropriate indexes, matching the read patterns of the current preferences_json usage"
      ]
    },
    "database_safety": {
      "has_migrations": true,
      "reversible": true,
      "data_preserving": false,
      "large_table_impact": true,
      "details": "Step 1 (CREATE TABLE) is safe and reversible. Step 3 (backfill) touches every row in the users table for reads and writes to the new table — on a large users table this has significant I/O impact. The backfill has a CRITICAL race condition with concurrent dual-writes that can silently lose recent preference updates. Step 6 (DROP COLUMN) is irreversible and destructive. The plan lacks batching details for the backfill — a single long-running transaction would lock the users table and cause an outage."
    },
    "verdict": "NOT READY"
  },

  "escalations": [
    {
      "type": "integration_gap",
      "issue": "Backfill-vs-dual-write race condition causes silent data loss",
      "reason": "When the backfill job (Step 3) runs concurrently with dual-writes (Step 2), it can read a user's old preference value, then the user updates their preferences via dual-write, then the backfill overwrites the new-table value with the stale data. This is a data-loss bug with no detection mechanism. The backfill must use conditional writes (e.g., UPDATE WHERE updated_at < source.updated_at) or the dual-write and backfill must coordinate via timestamps. This is an architectural gap that needs MJ's input on the correct consistency strategy.",
      "routed_to": "MJ"
    },
    {
      "type": "integration_gap",
      "issue": "No validation gate between backfill completion and read switchover",
      "reason": "Step 4 (switch reads to new table) has no prerequisite check that Step 3 (backfill) actually completed successfully for all users. Combined with the non-resumable backfill and the lack of a feature flag, this means the read switch could be deployed while an unknown number of users have no preferences in the new table. Needs architectural decision: add a validation query as a deployment gate, add a read-path fallback, or add a feature flag for coordinated switchover.",
      "routed_to": "MJ"
    }
  ],

  "confidence": {
    "level": 60,
    "high_confidence_areas": [
      "The backfill race condition is a real data-loss risk — this is a well-known pattern failure in dual-write migrations",
      "The lack of backfill validation before read switchover is a clear operational gap",
      "The missing observability makes this migration un-debuggable in production"
    ],
    "low_confidence_areas": [
      "Exact table sizes and whether the backfill I/O would cause production impact — depends on row count and indexing",
      "Whether the application has existing feature-flag infrastructure that could be leveraged",
      "Whether the dual-write implementation handles partial failures (one write succeeds, other fails)"
    ],
    "assumptions": [
      "The backfill job is a single-pass batch job without timestamp-based conditional writes",
